mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM semester
    WHERE user_id = #{reqUserId}
      AND semester_name = #{semesterName}
      AND deleted = false
)

mapper.sql:
WHERE semester.id is not null
AND semester.deleted = #{req.deleted}
AND semester.semester_name = #{req.semesterName}
AND semester.user_id = #{reqUserId}
